/**
 * Generated by scripts/gen-type-applicability.ts — do not hand-edit.
 *
 * Per-(block, name) applicability records: which AM4 amp / drive /
 * delay / reverb / etc. types expose this knob. Decoded from the
 * AM4-Edit BinaryData ZIP `__block_layout(.expert).xml` `<Page>`
 * and `<EditorControl>` per-type filter attributes
 * (2026-05-04 — replaces the earlier framing of "Ghidra-into-DSP
 * needed"; the data was always in the XML).
 *
 * Keys match `KNOWN_PARAMS` (e.g. `delay.right_post_delay`). For
 * params not in this map: assume always-on (the common case for
 * universal block params like `BLOCK_PAN` / `BLOCK_MIX` / out-of-
 * band channel/level registers).
 *
 * `always: true` means the parameter has at least one ungated UI
 * exposure. `gates` lists every type-enum gate the XML defines for
 * this parameter — useful as informational context (e.g. "this
 * knob is on a special Friedman BE page in addition to the
 * universal one"). When `always: false`, only types listed in
 * `gates` expose the knob in AM4-Edit's UI.
 */

export interface ApplicabilityGate {
  /** AM4-Edit symbolic enum that gates this parameter — e.g. `DELAY_TYPE`, `FUZZ_TYPE`. */
  readonly typeEnum: string;
  /** Wire indices into the gate enum at which this parameter is exposed. */
  readonly values: readonly number[];
  /** Whether the gate is on the entire `<Page>` or an individual `<EditorControl>`. */
  readonly source: 'page' | 'control';
}

export interface Applicability {
  /** True if the parameter has at least one ungated UI exposure. */
  readonly always: boolean;
  /** Type-enum gates the parameter has. May be present alongside `always: true` (special-cased pages). */
  readonly gates: readonly ApplicabilityGate[];
}

